SELECT predicted_price, confidence_level
FROM stock_predictions
WHERE stock_id = 1 AND user_id = 1 AND prediction_date = '2023-05-01';

SELECT AVG(rating) AS average_rating
FROM stock_ratings
WHERE stock_id = 1;

SELECT COUNT(comment_id) AS comment_count
FROM stock_comments
WHERE stock_id = 1;

SELECT COUNT(user_id) AS user_count
FROM stock_watchlists
WHERE stock_id = 1 AND removed_date IS NULL;

SELECT AVG(predicted_price) AS average_predicted_price
FROM stock_predictions
WHERE stock_id = 0;
